<style>
    .health-gauge {
        width: 160px; height: 160px; border-radius: 50%;
        background: conic-gradient(#5cb85c 0% @(Model.HealthScore.OverallScore)%, #eee @(Model.HealthScore.OverallScore)% 100%);
